    pub fn question_token(&self, node: Node) -> Option<Node> {
        let question_token = match self.header(node).payload.tag() {
            NodePayloadTag::ParameterDeclaration => {
                self.optional_node_from_id(self.as_parameter_declaration(node).question_token)
            }
            NodePayloadTag::ConditionalExpression => {
                self.optional_node_from_id(self.as_conditional_expression(node).question_token)
            }
            NodePayloadTag::MappedTypeNode => {
                self.optional_node_from_id(self.as_mapped_type_node(node).question_token)
            }
            NodePayloadTag::NamedTupleMember => {
                self.optional_node_from_id(self.as_named_tuple_member(node).question_token)
            }
            _ => None,
        };
        if question_token.is_some() {
            return question_token;
        }
        let postfix = self.postfix_token(node);
        if postfix.is_some_and(|postfix| self.kind(postfix) == Kind::QuestionToken) {
            return postfix;
        }
        None
    }

