                | NodePayloadTag::ImportDeclaration
                | NodePayloadTag::NamedImports
                | NodePayloadTag::ExportAssignment
                | NodePayloadTag::NamedExports
                | NodePayloadTag::ExportSpecifier
                | NodePayloadTag::ConstructorDeclaration
                | NodePayloadTag::GetAccessorDeclaration
                | NodePayloadTag::SetAccessorDeclaration
                | NodePayloadTag::MethodDeclaration
                | NodePayloadTag::PropertyDeclaration
                | NodePayloadTag::ClassStaticBlockDeclaration
                | NodePayloadTag::BinaryExpression
                | NodePayloadTag::ArrowFunction
                | NodePayloadTag::FunctionExpression
                | NodePayloadTag::ConditionalExpression
                | NodePayloadTag::PropertyAccessExpression
                | NodePayloadTag::ElementAccessExpression
                | NodePayloadTag::CallExpression
                | NodePayloadTag::NewExpression
                | NodePayloadTag::MetaProperty
                | NodePayloadTag::TemplateExpression
                | NodePayloadTag::TaggedTemplateExpression
                | NodePayloadTag::ArrayLiteralExpression
                | NodePayloadTag::ObjectLiteralExpression
                | NodePayloadTag::PropertyAssignment
                | NodePayloadTag::ShorthandPropertyAssignment
                | NodePayloadTag::ExpressionWithTypeArguments
