    pub fn has_statement_base(&self, node: Node) -> bool {
        matches!(
            self.header(node).payload.tag(),
            NodePayloadTag::EmptyStatement
                | NodePayloadTag::IfStatement
                | NodePayloadTag::DoStatement
                | NodePayloadTag::WhileStatement
                | NodePayloadTag::ForStatement
                | NodePayloadTag::ForInOrOfStatement
                | NodePayloadTag::BreakStatement
                | NodePayloadTag::ContinueStatement
                | NodePayloadTag::ReturnStatement
                | NodePayloadTag::WithStatement
                | NodePayloadTag::SwitchStatement
                | NodePayloadTag::ThrowStatement
                | NodePayloadTag::TryStatement
                | NodePayloadTag::DebuggerStatement
                | NodePayloadTag::LabeledStatement
                | NodePayloadTag::ExpressionStatement
                | NodePayloadTag::Block
                | NodePayloadTag::VariableStatement
                | NodePayloadTag::MissingDeclaration
                | NodePayloadTag::FunctionDeclaration
                | NodePayloadTag::ClassDeclaration
                | NodePayloadTag::InterfaceDeclaration
                | NodePayloadTag::TypeAliasDeclaration
                | NodePayloadTag::EnumDeclaration
                | NodePayloadTag::ModuleBlock
                | NodePayloadTag::NotEmittedStatement
                | NodePayloadTag::ImportDeclaration
                | NodePayloadTag::ExportAssignment
                | NodePayloadTag::NamespaceExportDeclaration
                | NodePayloadTag::ModuleDeclaration
                | NodePayloadTag::ImportEqualsDeclaration
                | NodePayloadTag::ExportDeclaration
        )
    }

