                let source_facts = AtomicU32::new(source_data.facts.load(Ordering::Relaxed));
                let source_clauses = source_data.clauses;
                let data = CaseBlock {
                    facts: Default::default(),
                    clauses: self.deep_clone_node_list_in_current_store_with_location(
                        source_clauses,
                        synthetic_location,
                    ),
                };
                let payload_idx = self.store.payloads_mut().case_block.alloc(data);
                let payload = NodePayloadId::new(NodePayloadTag::CaseBlock, payload_idx.into_raw());
