    fn deep_clone_binary_expression_chain_from_store_with_location(
        &mut self,
        source: &AstStore,
        node: Node,
        synthetic_location: bool,
    ) -> Node {
        let mut stack = vec![(node, false)];
        let mut cloned_nodes = source.new_node_map::<Node>();

        while let Some((current, expanded)) = stack.pop() {
            if cloned_nodes.contains_key(current) {
                continue;
            }
            if !expanded {
                stack.push((current, true));
                if let Some(right) = source.right(current) {
                    if source.kind(right) == Kind::BinaryExpression {
                        stack.push((right, false));
                    }
                }
                if let Some(left) = source.left(current) {
                    if source.kind(left) == Kind::BinaryExpression {
                        stack.push((left, false));
                    }
                }
                continue;
            }

            let source_data = source.as_binary_expression(current);
            let modifiers = source_data.modifiers.get().map(|id| {
                self.deep_clone_modifier_list_from_store_with_location(
                    source,
                    id,
                    synthetic_location,
                )
            });
            let left = self.deep_clone_binary_expression_child_from_store_with_location(
                source,
                source.optional_node_from_id(source_data.left),
                synthetic_location,
                &cloned_nodes,
            );
            let type_node = self.deep_clone_binary_expression_child_from_store_with_location(
                source,
                source.optional_node_from_id(source_data.r#type),
                synthetic_location,
                &cloned_nodes,
            );
            let operator_token = self.deep_clone_binary_expression_child_from_store_with_location(
                source,
                source.optional_node_from_id(source_data.operator_token),
                synthetic_location,
                &cloned_nodes,
            );
            let right = self.deep_clone_binary_expression_child_from_store_with_location(
                source,
                source.optional_node_from_id(source_data.right),
                synthetic_location,
                &cloned_nodes,
            );

            let cloned = self.new_binary_expression(
                modifiers.map(ModifierList::from_id),
                left,
                type_node,
                operator_token,
                right,
            );
            let cloned =
                self.finish_clone_node(cloned, current, source.flags(current), source.loc(current));
            if synthetic_location {
                self.store.set_loc(cloned, core::undefined_text_range());
            }
            cloned_nodes.insert(current, cloned);
        }

        cloned_nodes
            .remove(node)
            .expect("binary expression chain root should be cloned")
    }

    fn deep_clone_binary_expression_child_from_store_with_location(
        &mut self,
        source: &AstStore,
        node: Option<Node>,
        synthetic_location: bool,
        cloned_nodes: &StoreNodeMap<Node>,
    ) -> Option<Node> {
        let node = node?;
        if source.kind(node) == Kind::BinaryExpression {
            return cloned_nodes.get_copied(node);
        }
        Some(self.deep_clone_node_from_store_with_location(source, node, synthetic_location))
    }

    pub(crate) fn deep_clone_node_list_from_store(
        &mut self,
        source: impl AsRef<AstStore>,
        id: NodeListId,
    ) -> NodeListId {
        let source = source.as_ref();
        self.deep_clone_node_list_from_store_with_location(source, id, true)
    }

    fn deep_clone_node_list_from_store_with_location(
        &mut self,
        source: &AstStore,
        id: NodeListId,
        synthetic_location: bool,
    ) -> NodeListId {
        let list = source.node_list(id);
        let loc = if synthetic_location {
            core::undefined_text_range()
        } else {
            list.loc()
        };
        let range = if synthetic_location {
            core::undefined_text_range()
        } else {
            list.range()
        };
        let has_trailing_comma = list.has_trailing_comma();
        let nodes: Vec<_> = list
            .iter()
            .map(|node| {
                self.deep_clone_node_from_store_with_location(source, node, synthetic_location)
            })
            .collect();
        if synthetic_location {
            if let Some(cloned_last) = nodes.last().copied() {
                if has_trailing_comma {
                    self.store
                        .set_loc(cloned_last, core::new_text_range(-2, -2));
                }
            }
        }
        self.new_node_list_with_trailing_comma(loc, range, nodes, has_trailing_comma)
            .id()
    }

    fn deep_clone_node_list_in_current_store_with_location(
        &mut self,
        id: NodeListId,
        synthetic_location: bool,
    ) -> NodeListId {
        let list = self.store.node_list(id);
        let source_nodes = list.iter().collect::<Vec<_>>();
        let source_loc = list.loc();
        let source_range = list.range();
        let source_has_trailing_comma = list.has_trailing_comma();
        let nodes: Vec<_> = source_nodes
            .iter()
            .copied()
            .map(|node| {
                self.deep_clone_node_in_current_store_with_location(node, synthetic_location)
            })
            .collect();
        let loc = if synthetic_location {
            core::undefined_text_range()
        } else {
            source_loc
        };
        let range = if synthetic_location {
            core::undefined_text_range()
        } else {
            source_range
        };
        if synthetic_location {
            if let Some(cloned_last) = nodes.last().copied() {
                if source_has_trailing_comma {
                    self.store
                        .set_loc(cloned_last, core::new_text_range(-2, -2));
                }
            }
        }
        self.new_node_list_with_trailing_comma(loc, range, nodes, source_has_trailing_comma)
            .id()
    }

