    pub fn update_variable_statement_from_store(
        &mut self,
        source: &AstStore,
        node: Node,
        modifiers: impl IntoOptionalModifierList,
        declaration_list: impl Into<Option<Node>>,
    ) -> Node {
        let original_kind = source.kind(node);
        let original_flags = source.flags(node);
        let original_loc = source.loc(node);
        let source_data = source.as_variable_statement(node).clone();
        let modifiers = modifiers.into_optional_modifier_list();
        let declaration_list = declaration_list.into();
        let changed = {
            (match modifiers {
                Some(list) => {
                    list.store_id() != source.store_id()
                        || Some(list.id()) != source_data.modifiers.get()
                }
                None => source_data.modifiers.get().is_some(),
            }) || declaration_list != source.optional_node_from_id(source_data.declaration_list)
        };
        if !changed {
            return if source.store_id() == self.store.store_id() {
                node
            } else {
                self.deep_clone_node_from_store_with_location(source, node, false)
            };
        }
        let modifiers = self.import_optional_update_modifier_list_from_store(source, modifiers);
        let declaration_list = self.import_update_node_from_store(source, declaration_list);
        self.update_variable_statement_with_metadata(
            node,
            &source_data,
            original_kind,
            original_flags,
            original_loc,
            modifiers,
            declaration_list,
        )
    }

