    fn update_tagged_template_expression_with_metadata(
        &mut self,
        node: Node,
        source_data: &TaggedTemplateExpression,
        original_kind: Kind,
        original_flags: NodeFlags,
        original_loc: core::TextRange,
        tag: impl Into<Option<Node>>,
        question_dot_token: impl Into<Option<Node>>,
        type_arguments: impl IntoOptionalNodeList,
        template: impl Into<Option<Node>>,
        flags: NodeFlags,
    ) -> Node {
        let tag = self.store.optional_local_node_id(tag.into());
        let question_dot_token = self.store.optional_local_node_id(question_dot_token.into());
        let type_arguments = type_arguments.into_optional_node_list().map(|list| {
            list.assert_store(self.store.store_id());
            list.id()
        });
        let type_arguments = OptionalNodeListId::from_option(type_arguments.into());
        let template = self.store.optional_local_node_id(template.into());
        let changed = {
            tag != source_data.tag
                || question_dot_token != source_data.question_dot_token
                || type_arguments != source_data.type_arguments
                || template != source_data.template
                || flags != original_flags
        };
        if changed {
            let data = TaggedTemplateExpression {
                facts: Default::default(),
                tag: tag,
                question_dot_token: question_dot_token,
                type_arguments: type_arguments,
                template: template,
            };
            let payload_idx = self
                .store
                .payloads_mut()
                .tagged_template_expression
                .alloc(data);
            let payload = NodePayloadId::new(
                NodePayloadTag::TaggedTemplateExpression,
                payload_idx.into_raw(),
            );
            let mut node_flags = NodeFlags::NONE;
            node_flags |= flags & NodeFlags::OPTIONAL_CHAIN;
            let updated = self.new_node(Kind::TaggedTemplateExpression, node_flags, payload);
            return self.finish_update_node(updated, node, original_flags, original_loc);
        }
        node
    }

