    fn update_property_assignment_with_metadata(
        &mut self,
        node: Node,
        source_data: &PropertyAssignment,
        original_kind: Kind,
        original_flags: NodeFlags,
        original_loc: core::TextRange,
        modifiers: impl IntoOptionalModifierList,
        name: impl Into<Option<Node>>,
        postfix_token: impl Into<Option<Node>>,
        type_node: impl Into<Option<Node>>,
        initializer: impl Into<Option<Node>>,
    ) -> Node {
        let modifiers = modifiers.into_optional_modifier_list().map(|list| {
            list.assert_store(self.store.store_id());
            list.id()
        });
        let modifiers = OptionalModifierListId::from_option(modifiers.into());
        let name = self.store.optional_local_node_id(name.into());
        let postfix_token = self.store.optional_local_node_id(postfix_token.into());
        let type_node = self.store.optional_local_node_id(type_node.into());
        let initializer = self.store.optional_local_node_id(initializer.into());
        let changed = {
            modifiers != source_data.modifiers
                || name != source_data.name
                || postfix_token != source_data.postfix_token
                || type_node != source_data.r#type
                || initializer != source_data.initializer
        };
        if changed {
            let data = PropertyAssignment {
                modifiers: modifiers,
                name: name,
                postfix_token: postfix_token,
                facts: Default::default(),
                r#type: type_node,
                initializer: initializer,
            };
            let payload_idx = self.store.payloads_mut().property_assignment.alloc(data);
            let payload =
                NodePayloadId::new(NodePayloadTag::PropertyAssignment, payload_idx.into_raw());
            let updated = self.new_node(Kind::PropertyAssignment, NodeFlags::NONE, payload);
            return self.finish_update_node(updated, node, original_flags, original_loc);
        }
        node
    }

